class BankAccount:
    def __init__(self, owner, balance):
        self.owner = owner
        # TODO: store as _balance to signal it's private
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount

    def get_balance(self):
        return self.balance

account = BankAccount("Alex", 1000)
account.deposit(500)
print(account.get_balance())

class BankAccount:
    def __init__(self, owner, balance):
        self.owner = owner
        self._balance = balance

    # TODO: add @property for balance

    def deposit(self, amount):
        self._balance += amount

account = BankAccount("Alex", 1000)
account.deposit(200)
print(account.balance)  # reads like an attribute, actually calls a method

